        if (errJson.message) {
          errorDetail = errJson.message;
        }
      } catch { /* ignore parse error */ }
      return jsonResponse({ success: false, error: errorDetail, errorCode: 'EMAIL_SEND_FAILED' }, 500);
    }

    console.log('OTP email sent successfully to:', email);
